using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System;
using System.Data.SqlClient;
using System.Threading.Tasks;

public static class LoggingFunction
{
    [FunctionName("LoggingFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequestData req,
        ILogger logger)
    {
        try
        {
            logger.LogInformation($"HTTP Method: {req.Method}");
            logger.LogInformation($"HTTP Path: {req.Path}");
            logger.LogInformation($"HTTP Query String: {string.Join(", ", req.Query)}");

            var headers = new StringBuilder();
            foreach (var header in req.Headers)
            {
                headers.AppendLine($"{header.Key}: {header.Value}");
            }
            logger.LogInformation(headers.ToString());

            if (!string.IsNullOrEmpty(req.Body))
            {
                using (var reader = new StreamReader(req.Body))
                {
                    var bodyContent = await reader.ReadToEndAsync();
                    logger.LogInformation($"HTTP Body: {bodyContent}");
                }
            }

            // Database query
            var connectionString = Environment.GetEnvironmentVariable("AzureWebJobsStorage");
            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                var command = new SqlCommand("SELECT * FROM Table", connection);
                var parameters = new SqlParameter[] { };

                logger.LogInformation($"Database Query: SELECT * FROM Table");
                logger.LogInformation($"Database Parameters: [{string.Join(", ", parameters)}]");

                using (var reader = await command.ExecuteReaderAsync())
                {
                    while (await reader.ReadAsync())
                    {
                        logger.LogInformation($"Database Row: [{reader[0]}]");
                    }
                }
            }

            return new OkResult();
        }
        catch (Exception ex)
        {
            logger.LogError(ex, "Error occurred");
            throw;
        }
    }
}